}

// fichier formulaires.ts
/// <reference path="validateurs.ts" />

namespace Formulaires {
  export interface Utilisateur {
    nom: string;
    email: string;
    telephone: string;
  }

  export function validerUtilisateur(u: Utilisateur): { valide: boolean; erreurs: string[] } {
    const erreurs: string[] = [];

    if (!Validateurs.estNonVide(u.nom)) {
      erreurs.push("Le nom est obligatoire.");
    }

    if (!Validateurs.estEmailValide(u.email)) {
      erreurs.push("L'email n'est pas valide.");
    }

    if (!Validateurs.estTelephoneCameroun(u.telephone)) {
      erreurs.push("Le téléphone doit être un numéro camerounais valide (6xxxxxxxx ou 9xxxxxxxx).");
    }

    return {
      valide: erreurs.length === 0,
      erreurs
    };
  }
}

// fichier main.ts
/// <reference path="formulaires.ts" />

const utilisateur1: Formulaires.Utilisateur = {
  nom: "Jean Mbarga",
  email: "jean@example.com",
  telephone: "691234567"
};

const utilisateur2: Formulaires.Utilisateur = {
  nom: "",
  email: "email_invalide",
  telephone: "123456789"
};

console.log("=== TEST UTILISATEUR 1 ===");
const resultat1 = Formulaires.validerUtilisateur(utilisateur1);
console.log("Valide :", resultat1.valide);
console.log("Erreurs :", resultat1.erreurs);

console.log("\n=== TEST UTILISATEUR 2 ===");
const resultat2 = Formulaires.validerUtilisateur(utilisateur2);
console.log("Valide :", resultat2.valide);
console.log("Erreurs :", resultat2.erreurs);

// Compilation : tsc --outFile bundle.js main.ts
